{
  "name": "The Dream Homes and Constructions",
  "description": "A premium real estate and construction website featuring property listings, architectural services, and an AI-powered real estate assistant.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Property {
  id: string;
  title: string;
  price: number;
  location: string;
  type: 'Residential' | 'Commercial' | 'Land';
  status: 'For Sale' | 'For Rent' | 'Constructing';
  beds?: number;
  baths?: number;
  sqft: number;
  image: string;
  description: string;
}

export interface Service {
  id: string;
  title: string;
  description: string;
  icon: string;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getGeminiAssistantResponse = async (history: ChatMessage[], userMessage: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(m => ({
          role: m.role === 'assistant' ? 'model' : 'user',
          parts: [{ text: m.content }]
        })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: "You are the AI Assistant for 'The Dream Homes and Constructions Ltd.', a premium real estate and construction company. Be professional, helpful, and knowledgeable about architecture, property buying, selling, and construction processes. Encourage users to contact the agency for specific viewings or quotes. Keep answers concise but elegant.",
        temperature: 0.7,
      },
    });

    return response.text || "I apologize, but I'm having trouble processing that request. Please contact our main office.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm sorry, I'm currently offline. Please try again later or contact us directly at +1 (800) DREAM-HOME.";
  }
};

import React from 'react';
import { Property } from '../types';
import { Link } from 'react-router-dom';

interface PropertyCardProps {
  property: Property;
}

const PropertyCard: React.FC<PropertyCardProps> = ({ property }) => {
  return (
    <div className="bg-white rounded-xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 border border-slate-100 group">
      <div className="relative h-64 overflow-hidden">
        <img
          src={property.image}
          alt={property.title}
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
        />
        <div className="absolute top-4 left-4">
          <span className={`px-3 py-1 text-xs font-bold rounded-full ${
            property.status === 'For Sale' ? 'bg-green-100 text-green-800' :
            property.status === 'For Rent' ? 'bg-blue-100 text-blue-800' :
            'bg-orange-100 text-orange-800'
          }`}>
            {property.status}
          </span>
        </div>
        {property.price > 0 && (
          <div className="absolute bottom-4 left-4 bg-white/90 backdrop-blur-md px-4 py-2 rounded-lg font-bold text-blue-900 shadow-sm">
            ${property.price.toLocaleString()}
          </div>
        )}
      </div>
      <div className="p-6">
        <div className="text-xs font-semibold text-slate-400 uppercase tracking-widest mb-1">{property.type}</div>
        <h3 className="text-xl font-bold text-slate-900 mb-2 group-hover:text-blue-900 transition-colors">{property.title}</h3>
        <p className="text-slate-500 flex items-center text-sm mb-4">
          <i className="fa-solid fa-location-dot mr-2 text-slate-400"></i>
          {property.location}
        </p>
        <div className="flex items-center justify-between pt-4 border-t border-slate-50">
          <div className="flex space-x-4 text-sm text-slate-600 font-medium">
