          <p className="text-slate-500">Try adjusting your filters or search criteria.</p>
          <button 
            onClick={() => {setFilter('All'); setStatusFilter('All');}}
            className="mt-6 text-blue-900 font-bold underline"
          >
            Clear all filters
          </button>
        </div>
      )}
    </div>
  );
};

export default Listings;

