import React, { useState, useEffect } from 'react';
import PropertyCard from '../components/PropertyCard';
import { db } from '../firebase';
import { collection, getDocs, query, orderBy } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const Listings: React.FC = () => {
  const [filter, setFilter] = useState<'All' | 'Residential' | 'Commercial' | 'Land'>('All');
  const [statusFilter, setStatusFilter] = useState<'All' | 'For Sale' | 'For Rent' | 'Constructing' | 'Sold'>('All');
  const [properties, setProperties] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProperties = async () => {
      try {
        const q = query(collection(db, "projects"), orderBy("createdAt", "desc"));
        const snapshot = await getDocs(q);
        setProperties(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchProperties();
  }, []);

  const filteredProperties = properties.filter(p => 
    (filter === 'All' || p.type === filter) &&
    (statusFilter === 'All' || p.status === statusFilter)
  );

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
      <div className="mb-12">
        <h1 className="text-5xl font-bold text-slate-900 mb-4 tracking-tighter uppercase">Project Collection</h1>
        <p className="text-slate-500 max-w-2xl text-lg font-medium">
          Explore our handpicked selection of premium residences, commercial hubs, and investment opportunities across Dhaka.
        </p>
      </div>

      {/* Filters */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex flex-wrap gap-2">
          {['All', 'Residential', 'Commercial', 'Land'].map((type) => (
            <button
              key={type}
              onClick={() => setFilter(type as any)}
              className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
                filter === type 
                  ? 'bg-royalGreen text-white shadow-md' 
                  : 'bg-slate-50 text-slate-600 hover:bg-slate-100'
              }`}
            >
              {type}
            </button>
          ))}
        </div>

        <div className="flex items-center space-x-3">
          <span className="text-sm font-bold text-slate-400 uppercase tracking-widest">Status:</span>
          <select 
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as any)}
            className="bg-slate-50 border-none rounded-xl px-4 py-2 text-sm font-semibold focus:ring-2 focus:ring-royalGreen outline-none"
          >
            <option value="All">All Statuses</option>
            <option value="For Sale">For Sale</option>
            <option value="For Rent">For Rent</option>
            <option value="Constructing">Constructing</option>
            <option value="Sold">Sold</option>
          </select>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><i className="fa-solid fa-spinner fa-spin text-4xl text-royalGreen"></i></div>
      ) : filteredProperties.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredProperties.map(property => (
            <PropertyCard key={property.id} property={property} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
          <i className="fa-solid fa-house-circle-exclamation text-4xl text-slate-300 mb-4"></i>
          <h3 className="text-xl font-bold text-slate-900 mb-2">No matching properties found</h3>
          <p className="text-slate-500">Try adjusting your filters or search criteria.</p>
        </div>
      )}
    </div>
  );
};

export default Listings;

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

// Correctly initialize GoogleGenAI with direct access to process.env.API_KEY as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getGeminiAssistantResponse = async (history: ChatMessage[], userMessage: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(m => ({
          role: m.role === 'assistant' ? 'model' : 'user',
          parts: [{ text: m.content }]
        })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: "You are the AI Assistant for 'The Dream Homes & Constructions Ltd.', a premium real estate and construction company based in Dhaka, Bangladesh. Our headquarters is at ECB Chattor, Dhaka Cantonment. We specialize in Purbachal 300ft, Mirpur DOHS, Trust Green City, and Shagupta. Be professional, helpful, and aware of the Bangladeshi real estate market. When asked about prices, provide ranges in BDT (৳). Encourage users to call us at +8801708364030 for specific plot visits or luxury apartment viewings.",
        temperature: 0.7,
      },
    });

    // Access .text property directly as per guidelines (not a method).
    return response.text || "I apologize, but I'm having trouble processing that request. Please contact our main office at +8801708364030.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm sorry, I'm currently offline. Please try again later or contact us directly at +8801708364030.";
  }
};

import React, { useEffect, useState } from 'react';
import { Navigate } from 'react-router-dom';
import { auth } from '../firebase';
import { onAuthStateChanged } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

// Explicitly define props to include children for better type compatibility in strict environments.
interface ProtectedRouteProps {
  children: React.ReactNode;
}

const ProtectedRoute = ({ children }: ProtectedRouteProps) => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      setUser(user);
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  if (loading) return <div className="h-screen flex items-center justify-center"><i className="fa-solid fa-spinner fa-spin text-royalGreen text-4xl"></i></div>;

  if (!user) {
    return <Navigate to="/" replace />;
  }

  return <>{children}</>;
};

export default ProtectedRoute;

