                <p className="text-slate-400 text-base mb-8 font-light">Our expert consultants are ready to assist you in securing your dream property.</p>
                <a href={`tel:${SITE_CONFIG.phone.replace(/\s+/g, '')}`} className="inline-flex items-center text-royalGold text-2xl font-bold hover:underline">
                    <i className="fa-solid fa-phone mr-3"></i> {SITE_CONFIG.phone}
                </a>
            </div>

            <div className="flex-1 w-full max-w-md bg-white p-8 rounded-3xl shadow-xl">
              <form onSubmit={handleLeadSubmit} className="space-y-4">
                <input required type="text" placeholder="Name" value={leadForm.name} onChange={e => setLeadForm({...leadForm, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 outline-none focus:ring-1 focus:ring-royalGold" />
                <input required type="email" placeholder="Email" value={leadForm.email} onChange={e => setLeadForm({...leadForm, email: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 outline-none focus:ring-1 focus:ring-royalGold" />
                <textarea required placeholder="Requirements" rows={3} value={leadForm.message} onChange={e => setLeadForm({...leadForm, message: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 outline-none focus:ring-1 focus:ring-royalGold resize-none"></textarea>
                <button disabled={formStatus === 'sending'} className="w-full bg-royalGreen text-white font-bold py-4 rounded-xl uppercase tracking-widest text-xs hover:bg-green-800">
                  {formStatus === 'success' ? 'Sent successfully' : 'Request Call'}
                </button>
              </form>
            </div>
        </div>
      </section>
    </div>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import { db, auth } from '../firebase';
import firebase from 'firebase/compat/app';
import { useNavigate } from 'react-router-dom';
import { SITE_CONFIG } from '../siteConfig';

const AdminDashboard = () => {
  const [activeTab, setActiveTab] = useState<'projects' | 'leads'>('projects');
  const [projects, setProjects] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    title: '', description: '', location: SITE_CONFIG.areas[0], priceRange: '', 
    status: 'For Sale', type: 'Residential', beds: '', baths: '', sqft: '', features: '',
    image: '', brochure: ''
  });
  const navigate = useNavigate();

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'projects') {
        const snapshot = await db.collection("projects").orderBy("createdAt", "desc").get();
        setProjects(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
      } else {
        const snapshot = await db.collection("leads").orderBy("timestamp", "desc").get();
        setLeads(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
      }
    } catch (err) {
      console.error("Error fetching data:", err);
    }
    setLoading(false);
  };

  const handleLogout = async () => {
    await auth.signOut();
    navigate('/');
  };

  const handleProjectSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const projectData = {
        ...formData,
        beds: formData.beds ? parseInt(formData.beds) : null,
        baths: formData.baths ? parseInt(formData.baths) : null,
        sqft: formData.sqft ? parseInt(formData.sqft) : 0,
        updatedAt: firebase.firestore.Timestamp.now()
      };

      if (editingId) {
        await db.collection("projects").doc(editingId).update(projectData);
      } else {
        await db.collection("projects").add({
          ...projectData,
          createdAt: firebase.firestore.Timestamp.now()
        });
      }

      setIsAdding(false);
      setEditingId(null);
      setFormData({ 
        title: '', description: '', location: SITE_CONFIG.areas[0], priceRange: '', 
        status: 'For Sale', type: 'Residential', beds: '', baths: '', 
        sqft: '', features: '', image: '', brochure: '' 
      });
      fetchData();
    } catch (err) {
      console.error(err);
      alert("Error saving project.");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (projectId: string) => {
    if (window.confirm("Are you sure you want to delete this project?")) {
      await db.collection("projects").doc(projectId).delete();
      fetchData();
    }
  };

  const handleEdit = (project: any) => {
    setEditingId(project.id);
    setFormData({
      title: project.title || '',
      description: project.description || '',
      location: project.location || SITE_CONFIG.areas[0],
      priceRange: project.priceRange || '',
      status: project.status || 'For Sale',
      type: project.type || 'Residential',
      beds: project.beds?.toString() || '',
      baths: project.baths?.toString() || '',
      sqft: project.sqft?.toString() || '',
      features: project.features || '',
      image: project.image || '',
      brochure: project.brochure || ''
    });
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex justify-between items-center mb-10 border-b pb-6">
        <div>
          <h1 className="text-xl font-bold text-royalGreen uppercase">{SITE_CONFIG.name}</h1>
          <p className="text-slate-500 text-[10px] font-bold tracking-widest uppercase">Admin Control</p>
        </div>
        <div className="flex items-center space-x-6">
          <button onClick={() => setActiveTab('projects')} className={`text-xs font-bold uppercase tracking-widest ${activeTab === 'projects' ? 'text-royalGreen' : 'text-slate-400'}`}>Inventory</button>
          <button onClick={() => setActiveTab('leads')} className={`text-xs font-bold uppercase tracking-widest ${activeTab === 'leads' ? 'text-royalGreen' : 'text-slate-400'}`}>Leads</button>
          <button onClick={handleLogout} className="text-red-500 text-xs font-bold uppercase tracking-widest border border-red-100 px-4 py-2 rounded-lg">Logout</button>
        </div>
      </div>

      {activeTab === 'projects' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-center">
            <h2 className="text-lg font-bold uppercase">{editingId ? 'Modify Project' : 'Inventory Management'}</h2>
            <button 
              onClick={() => { setIsAdding(!isAdding); if(isAdding) setEditingId(null); }}
              className="bg-royalGreen text-white px-5 py-2 rounded-lg font-bold text-[10px] uppercase tracking-widest"
            >
              {isAdding ? 'Close Form' : 'Add New Project'}
            </button>
          </div>

          {isAdding && (
            <form onSubmit={handleProjectSubmit} className="bg-white p-8 rounded-2xl border border-slate-100 shadow-xl grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2 space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Project Title</label>
                <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none" />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Full Description</label>
                <textarea required rows={3} value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none resize-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Strategic Location</label>
                <select value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none">
                   {SITE_CONFIG.areas.map(area => <option key={area} value={area}>{area}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Price String (e.g. 75 Lac)</label>
                <input required type="text" value={formData.priceRange} onChange={e => setFormData({...formData, priceRange: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Image URL</label>
                <input required type="url" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Brochure URL (PDF Link)</label>
                <input type="url" value={formData.brochure} onChange={e => setFormData({...formData, brochure: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none" placeholder="Optional PDF link" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Features (Comma separated)</label>
                <input type="text" value={formData.features} onChange={e => setFormData({...formData, features: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none" placeholder="Parking, Pool, Security" />
              </div>
              <div className="grid grid-cols-3 gap-3 items-end">
                <div className="space-y-1">
                   <label className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Beds</label>
                   <input type="number" value={formData.beds} onChange={e => setFormData({...formData, beds: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-2 py-3 outline-none" />
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Baths</label>
                   <input type="number" value={formData.baths} onChange={e => setFormData({...formData, baths: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-2 py-3 outline-none" />
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Sqft</label>
                   <input type="number" value={formData.sqft} onChange={e => setFormData({...formData, sqft: e.target.value})} className="w-full bg-slate-50 border rounded-xl px-2 py-3 outline-none" />
                </div>
              </div>
              <div className="md:col-span-2">
                <button type="submit" disabled={loading} className="w-full bg-royalGreen text-white font-bold py-4 rounded-xl shadow-lg uppercase tracking-widest text-[11px] hover:bg-green-800 disabled:opacity-50">
                  {loading ? 'Processing...' : editingId ? 'Update project' : 'Add to inventory'}
                </button>
              </div>
            </form>
          )}

          <div className="bg-white rounded-xl border overflow-hidden shadow-sm">
            <table className="w-full text-left text-xs">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-6 py-4 font-bold uppercase tracking-widest text-slate-400">Project</th>
                  <th className="px-6 py-4 font-bold uppercase tracking-widest text-slate-400">Location</th>
                  <th className="px-6 py-4 text-right font-bold uppercase tracking-widest text-slate-400">Action</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {projects.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50">
                    <td className="px-6 py-4 font-bold text-slate-700">{p.title}</td>
                    <td className="px-6 py-4 text-slate-500">{p.location}</td>
                    <td className="px-6 py-4 text-right space-x-4 uppercase font-bold text-[10px] tracking-widest">
                      <button onClick={() => handleEdit(p)} className="text-royalGold">Edit</button>
                      <button onClick={() => handleDelete(p.id)} className="text-red-400">Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'leads' && (
        <div className="animate-in fade-in duration-500">
           {/* Inquiry handling */}
           <div className="grid grid-cols-1 gap-4">
              {leads.map(lead => (
                <div key={lead.id} className="bg-white p-6 rounded-xl border shadow-sm">
                  <div className="flex justify-between mb-2">
                    <h3 className="font-bold text-slate-700">{lead.name}</h3>
                    <span className="text-[10px] text-slate-400 uppercase font-bold">{new Date(lead.timestamp?.toDate()).toLocaleDateString()}</span>
                  </div>
                  <p className="text-xs text-slate-500 mb-2">{lead.email} | {lead.phone}</p>
                  <p className="text-xs text-slate-600 bg-slate-50 p-3 rounded-lg italic">"{lead.message}"</p>
                </div>
              ))}
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { SITE_CONFIG } from '../siteConfig';

interface NavbarProps {
  user?: any;
}

const Navbar: React.FC<NavbarProps> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  const isHomePage = location.pathname === '/';
  const isActive = (path: string) => location.pathname === path;

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 80);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isTransparent = isHomePage && !isScrolled;

  const NavLink = ({ to, children, active }: { to: string, children?: React.ReactNode, active?: boolean }) => (
    <Link 
      to={to} 
      className={`
        ${active 
          ? (isTransparent ? 'text-white border-b-2 border-white' : 'text-royalGreen border-b-2 border-royalGreen') 
          : (isTransparent ? 'text-white/80 hover:text-white' : 'text-slate-600 hover:text-royalGreen')
        } 
        font-bold transition-all px-2 py-1 text-[11px] uppercase tracking-wider whitespace-nowrap
      `}
    >
      {children}
    </Link>
  );

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-500 ${isTransparent ? 'bg-transparent py-4' : 'bg-white shadow-md border-b border-slate-200 py-2'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20 items-center">
          <div className="flex items-center">
            <Link to="/" className="flex-shrink-0 flex items-center group">
              <div className={`p-2 rounded-2xl backdrop-blur-md transition-all duration-500 ${isTransparent ? 'bg-white/10 border border-white/20' : 'bg-royalGreen/5 border border-royalGreen/10'}`}>
                <img src={SITE_CONFIG.logo} alt="Logo" className="h-14 md:h-16 w-auto object-contain" />
              </div>
              <div className="flex flex-col ml-4">
                <span className={`text-base sm:text-lg font-bold tracking-tight leading-none uppercase transition-colors ${isTransparent ? 'text-white' : 'text-royalGreen'}`}>
                  {SITE_CONFIG.name}
                </span>
                <div className="flex justify-between w-full mt-1 px-[1px]">
                   {SITE_CONFIG.tagline.split("").map((char, i) => (
                     <span key={i} className={`text-[9px] md:text-[10px] font-bold uppercase leading-tight tracking-tighter transition-colors ${isTransparent ? 'text-white/70' : 'text-royalGold'}`}>
                       {char === " " ? "\u00A0" : char}
                     </span>
                   ))}
                </div>
              </div>
            </Link>
          </div>

          <div className="hidden lg:flex items-center space-x-5">
            <NavLink to="/" active={isActive('/')}>Home</NavLink>
            <NavLink to="/listings" active={isActive('/listings')}>Projects</NavLink>
            <NavLink to="/services" active={isActive('/services')}>Services</NavLink>
            <NavLink to="/contact" active={isActive('/contact')}>Contact Us</NavLink>

            <div className={`h-6 w-[1px] mx-2 ${isTransparent ? 'bg-white/20' : 'bg-slate-200'}`}></div>

            {user ? (
              <Link to="/admin" className="bg-royalGold text-white px-5 py-2 rounded-lg hover:bg-amber-600 transition-all font-bold text-[10px] uppercase tracking-widest shadow-sm">
                Dashboard
              </Link>
            ) : (
              <Link to="/login" className={`font-bold text-[10px] uppercase tracking-widest flex items-center transition-colors ${isTransparent ? 'text-white hover:text-white/80' : 'text-royalGreen hover:text-green-800'}`}>
                <i className="fa-solid fa-user-lock mr-2"></i> Login
              </Link>
            )}
          </div>

          <div className="lg:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={`inline-flex items-center justify-center p-2 rounded-md ${isTransparent ? 'text-white' : 'text-slate-400 hover:text-royalGreen'}`}
            >
              <i className={`fa-solid ${isOpen ? 'fa-xmark' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="lg:hidden bg-white border-t border-slate-100 shadow-xl overflow-hidden animate-in slide-in-from-top-4 duration-300">
          <div className="px-4 pt-2 pb-6 space-y-1">
            <Link to="/" onClick={() => setIsOpen(false)} className={`block px-3 py-3 text-sm font-bold rounded-lg ${isActive('/') ? 'bg-royalGreen text-white' : 'text-slate-700'}`}>Home</Link>
            <Link to="/listings" onClick={() => setIsOpen(false)} className={`block px-3 py-3 text-sm font-bold rounded-lg ${isActive('/listings') ? 'bg-royalGreen text-white' : 'text-slate-700'}`}>Projects</Link>
            <Link to="/services" onClick={() => setIsOpen(false)} className={`block px-3 py-3 text-sm font-bold rounded-lg ${isActive('/services') ? 'bg-royalGreen text-white' : 'text-slate-700'}`}>Services</Link>
            <Link to="/contact" onClick={() => setIsOpen(false)} className={`block px-3 py-3 text-sm font-bold rounded-lg ${isActive('/contact') ? 'bg-royalGreen text-white' : 'text-slate-700'}`}>Contact Us</Link>
            <div className="pt-2">
              {user ? (
                <Link to="/admin" onClick={() => setIsOpen(false)} className="block px-4 py-3 text-center text-sm font-bold text-white bg-royalGold rounded-lg">Dashboard</Link>
              ) : (
                <Link to="/login" onClick={() => setIsOpen(false)} className="block px-4 py-3 text-center text-sm font-bold text-white bg-royalGreen rounded-lg">Login</Link>
              )}
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { SERVICES, PROPERTIES } from '../constants'; 
import PropertyCard from '../components/PropertyCard';
import { db, isFirebaseConfigured } from '../firebase';
import firebase from 'firebase/compat/app';
import { SITE_CONFIG } from '../siteConfig';

const Home: React.FC = () => {
  const [featuredProjects, setFeaturedProjects] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [leadForm, setLeadForm] = useState({ name: '', email: '', message: '' });
  const [formStatus, setFormStatus] = useState<'idle' | 'sending' | 'success' | 'error'>('idle');

  useEffect(() => {
    const fetchProjects = async () => {
      if (!isFirebaseConfigured || !db) {
        setFeaturedProjects(PROPERTIES.slice(0, 3));
        setLoading(false);
        return;
      }

      try {
        const snapshot = await db.collection("projects").orderBy("createdAt", "desc").limit(3).get();
        if (snapshot.empty) {
          setFeaturedProjects(PROPERTIES.slice(0, 3));
        } else {
          setFeaturedProjects(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
        }
      } catch (err) {
        console.error("Error fetching projects from Firebase:", err);
        setFeaturedProjects(PROPERTIES.slice(0, 3)); 
      } finally {
        setLoading(false);
      }
    };
    fetchProjects();
  }, []);

  const handleLeadSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFirebaseConfigured || !db) {
      alert(`Contact form is currently in demo mode. Please contact us at ${SITE_CONFIG.phone}`);
      return;
    }

    setFormStatus('sending');
    try {
      await db.collection("leads").add({
        ...leadForm,
        timestamp: firebase.firestore.Timestamp.now(),
        source: 'Home Callback Form'
      });
      setFormStatus('success');
      setLeadForm({ name: '', email: '', message: '' });
      setTimeout(() => setFormStatus('idle'), 3000);
    } catch (err) {
      console.error(err);
      setFormStatus('error');
      setTimeout(() => setFormStatus('idle'), 3000);
    }
  };

  return (
    <div className="space-y-16">
      {/* Hero Section */}
      <section className="relative h-[85vh] flex items-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src="https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?auto=format&fit=crop&q=80&w=1920" 
            alt="Luxury Home Dhaka" 
            className="w-full h-full object-cover animate-slow-zoom"
          />
          <div className="absolute inset-0 bg-gradient-to-r from-royalGreen/70 via-royalGreen/40 to-transparent"></div>
        </div>

        <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-20">
          <div className="max-w-2xl p-10 rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl">
            <h1 className="text-4xl md:text-6xl font-bold leading-tight mb-6 text-white uppercase tracking-tight">
              Build Your <span className="text-royalGold">Legacy</span>
            </h1>
            <p className="text-base md:text-xl text-white/90 mb-10 leading-relaxed font-light">
              Premium plots and luxury residences across Bangladesh's most elite development zones. Architectural brilliance meets timeless value.
            </p>
            <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-5">
              <Link to="/listings" className="bg-royalGold hover:bg-amber-600 text-white px-8 py-4 rounded-xl text-center font-bold transition-all text-sm uppercase tracking-widest shadow-lg">
                Explore Projects
              </Link>
              <a href="#leads" className="bg-white/20 backdrop-blur-xl hover:bg-white/30 border border-white/30 text-white px-8 py-4 rounded-xl text-center font-bold transition-all text-sm uppercase tracking-widest">
                Contact Us
              </a>
            </div>
          </div>
        </div>
      </section>

      {/* Strategic Focus Areas */}
      <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="text-center mb-16">
          <h2 className="text-2xl md:text-4xl font-bold text-slate-900 mb-4 uppercase tracking-tight">Our Strategic Focus Areas</h2>
          <div className="h-1 w-24 bg-royalGold mx-auto rounded-full"></div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {SITE_CONFIG.areas.map((area, index) => (
            <div key={index} className="relative h-64 rounded-[2rem] overflow-hidden group cursor-pointer shadow-lg">
